import type { Component } from "solid-js";
import { parse } from "marked";

import styles from "./App.module.css";

import { createSignal, createEffect, createResource } from "solid-js";
import TypeIt from "typeit";

const chatsDir = "chats/";

function sleepMs(ms: number) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function formatFileName(filename: string) {
  return filename.replace(".json", "").replace(/-/g, " ");
}

// ✅ 상태 관리 (Recoil -> Solid signals)
const [currentTab, setCurrentTab] = createSignal<string>("");
const [chatFiles] = createResource<string[]>(async () => {
  try {
    const response = await fetch(chatsDir + "index.json");
    if (!response.ok) throw new Error("Failed to load chat index");
    const data = await response.json();
    return data.files || [];
  } catch (error) {
    console.error("Fetch failed:", error);
    return [];
  }
});

const [chatMessages] = createResource(currentTab, async (tab) => {
  if (!tab) return [];
  try {
    const response = await fetch(chatsDir + tab);
    if (!response.ok) throw new Error("Failed to load chat data");
    const data = await response.json();
    return data.messages || [];
  } catch (error) {
    console.error("Fetch failed:", error);
    return [];
  }
});

// ✅ 탭 컴포넌트
function Tabs() {
  createEffect(() => {
    const files = chatFiles();
    if (files && files.length > 0 && !currentTab()) {
      setCurrentTab(files[0]);
    }
  });

  return (
    <div class="tabs">
      {chatFiles()?.map((file) => (
        <div
          class={`tab ${currentTab() === file ? "active" : ""}`}
          onClick={() => setCurrentTab(file)}
        >
          {formatFileName(file)}
        </div>
      ))}
    </div>
  );
}

type ChatMessage = {
  sender: number;
  message: string;
};

type VisibleMessage = ChatMessage & { id: number };

// ✅ 채팅 피드 컴포넌트
function ChatFeed() {
  const [visibleMessages, setVisibleMessages] = createSignal<VisibleMessage[]>(
    []
  );
  const [isAtBottom, setIsAtBottom] = createSignal<boolean>(true);

  let isAtBottomRef: boolean = true;
  let chatContainerRef: HTMLDivElement | undefined;

  const checkIsAtBottom = () => {
    if (!chatContainerRef) return true;
    const { scrollTop, scrollHeight, clientHeight } = chatContainerRef;
    const margin = 50;
    setIsAtBottom(scrollTop + clientHeight >= scrollHeight - margin);
  };

  createEffect(() => {
    isAtBottomRef = isAtBottom();
    scrollToBottomByPeriod();
  });

  function scrollToBottomByPeriod() {
    if (!isAtBottomRef) return;
    // console.log("isAtBottomRef.current:", isAtBottomRef.current);
    // console.log("chatContainerRef.current:", chatContainerRef.current);
    if (chatContainerRef) {
      chatContainerRef.scrollTop = chatContainerRef.scrollHeight;
    }
    setTimeout(scrollToBottomByPeriod, 1000);
  }

  createEffect(() => {
    isAtBottomRef = isAtBottom(); // ✅ 최신 값을 ref에 동기화
    scrollToBottomByPeriod();
  });

  async function loadMessages(chatMessages: ChatMessage[]) {
    for (const [msgId, msg] of chatMessages.entries()) {
      if (visibleMessages().some((m) => m.id === msgId)) continue;

      setVisibleMessages((prev) => [...prev, { ...msg, id: msgId }]);
      const checkElement = () => {
        if (document.getElementById(`msg-${msgId}`)) return;
        console.log(
          `Element #msg-${msgId} not found, sleep 100ms, retrying...`
        );
        setTimeout(checkElement, 100);
      };

      const inst = new TypeIt(`#msg-${msgId}`, {
        strings: [parse(msg.message, { async: false })],
        speed: 50,
        waitUntilVisible: true,
        afterComplete: () => {
          inst.destroy();
          setTimeout(() => {}, 1000);
        },
      }).go();
    }
  }

  createEffect(async () => {
    if (!chatMessages() || chatMessages().length === 0) return;
    await loadMessages(chatMessages());
  });

  return visibleMessages().length === 0 ? (
    <div class={styles.chatContainer}>Loading messages...</div>
  ) : (
    <div
      ref={chatContainerRef}
      class="chat-container"
      onScroll={checkIsAtBottom}
    >
      {visibleMessages().map((msg) => (
        <div class={`message ${msg.sender === 1 ? "user" : "bot"}`}>
          <div id={`msg-${msg.id}`} class="bubble">
            {msg.message}
          </div>
        </div>
      ))}
    </div>
  );
}

// ✅ 메인 앱 컴포넌트
const App: Component = () => {
  const [isTabsOpen, setIsTabsOpen] = createSignal(true);

  return (
    <div class={styles.container}>
      <div class={styles.tabsContainer}>
        <button
          class={styles.toggleTabsButton}
          onClick={() => setIsTabsOpen(!isTabsOpen())}
        >
          {isTabsOpen() ? "<<" : ">>"}
        </button>
        {isTabsOpen() && <Tabs />}
      </div>
      <ChatFeed />
    </div>
  );
};

export default App;
